from typing import List
from collections import defaultdict

class Solution:
    def maximumTotalDamage(self, power: List[int]) -> int:
        freq = defaultdict(int)
        for p in power:
            freq[p] += p  # Store total damage for each unique power value

        unique_powers = sorted(freq.keys())
        n = len(unique_powers)
        dp = [0] * n

        for i in range(n):
            # Take current power's total damage
            current_total = freq[unique_powers[i]]
            dp[i] = current_total

            # Check for non-conflicting previous powers
            for j in range(i):
                if abs(unique_powers[i] - unique_powers[j]) > 2:
                    dp[i] = max(dp[i], dp[j] + current_total)

        return max(dp)
